ifMode.script:
jQuery(function() {
    var allowedToEditDate = false;
    var allowedToEditProvider = false;



        allowedToEditProvider = true;
        allowedToEditDate = true;




        allowedToEditDate = true;


    if (!allowedToEditDate) {
        getField('encounterDate.value').prop('disabled', true);
        // we need to enable the field upon submission so that it actually gets submitted
        beforeSubmit.push(function() {
            getField('encounterDate.value').prop('disabled', false);
            return true;
        });
        afterSubmitFailure.push(function() {
            getField('encounterDate.value').prop('disabled', true);
        });
    }

    if (!allowedToEditProvider) {
        // since there can be multiple encounterProviderAndRole tags on a form HFE provides no direct way to reference it
        jq('#who').find('select').first().prop('disabled', true);
        // we need to enable the field upon submission so that it actually gets submitted
        beforeSubmit.push(function() {
            jq('#who').find('select').first().prop('disabled', false);
            return true;
        });
        afterSubmitFailure.push(function() {
            jq('#who').find('select').first().prop('disabled', true);
        });
        // handle the error state when the user is not a valid provider for the form and doesn't have rights to change the provider
        if (!jq('#who').find('select').first().val()) {
            // if we are in one-question-per-screen effectively disable the form by adding an exit handler to the encounterProvider selector that always returns false
            if (typeof NavigatorController !== "undefined") {
                NavigatorController.getFieldByContainerId('who').exitHandlers.push({
                    handleExit: function (fieldValue) {
                        return false;
                    }
                });
            }
            jq('#invalid-user').show();  // display error message
        }
     }

});
